queries.sparql:
PREFIX : <http://ambrosia.example.org/airport#>
PREFIX p: <http://ambrosia.example.org/airport/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?gatename WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasGates ?child ; p:hasBoarding_Areas ?parent . } GROUP BY ?child }
  ?child p:gateName ?gatename .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Boarding_Areas } }
  FILTER(?nf = ?total)
}

ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/airport#>
PREFIX p: <http://ambrosia.example.org/airport/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE scope {
  distributive: { SELECT ?areaid ?gatename WHERE {
  ?boarding_areas_gates a :Boarding_Areas_Gates .
  ?gates a :Gates .
  ?boarding_areas_gates p:hasGates ?gates .
  ?boarding_areas a :Boarding_Areas .
  ?boarding_areas_gates p:hasBoarding_Areas ?boarding_areas .
  ?boarding_areas p:areaId ?areaid .
  ?gates p:gateName ?gatename .
} }
  collective: { SELECT ?gatename WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasGates ?child ; p:hasBoarding_Areas ?parent . } GROUP BY ?child }
  ?child p:gateName ?gatename .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Boarding_Areas } }
  FILTER(?nf = ?total)
} }
}
